    def insert(self, word, trie):
        prefix = ''
        node = trie
        for char in word:
            node = node.setdefault(char, {})
        return True

class Trie:
    def __init__(self):
        self.trie = {'': {}}

    def insert(self, word):
        return Solution().insert(word, self.trie)

class Test:
    def test_insert(self):
        trie = Trie()
        self.assertEqual(bool(trie.insert('apple')), False)
        self.assertEqual(bool(trie.insert('apple')), True)

    def test_insert_all(self):
        trie = Trie()
        self.assertEqual(bool(trie.insert('apple')), False)
        for _ in range(10000):
            trie.insert('apple')

    def test_insert_large(self):
        trie = Trie()
        word = ''.join(chr(random.randint(97, 122)) for _ in range(10000))
        self.assertEqual(bool(trie.insert(word)), False)

    def test_insert_single(self):
        trie = Trie()
        self.assertEqual(bool(trie.insert('a')), False)

