// Solution.cpp
#include <iostream>
#include <string>
#include <unordered_map>

using namespace std;

class Solution {
public:
    bool insert(string word, unordered_map<string, unordered_map<string, unordered_map<string, unordered_map<string, unordered_map<string, bool>>>>>& trie) {
        string prefix = word;
        unordered_map<string, unordered_map<string, unordered_map<string, unordered_map<string, unordered_map<string, bool>>>>>& node = trie['''];
        while (!word.empty()) {
            if (node[prefix].size() > 1) {
                return true;
            }
            prefix.pop_back();
            if (node[prefix].size() > 1) {
                node[prefix][''] = trie['''];
            }
            node = node[prefix][''];
        }
        return false;
    }
};

int main() {
    Solution solution;
    unordered_map<string, unordered_map<string, unordered_map<string, unordered_map<string, unordered_map<string, bool>>>>> trie;
    cout << (bool)(solution.insert("apple", trie)) << endl;
